const item = $input.first() || { json: {} };
const raw = item.json || {};
const body = raw.body || raw;
const candidate_id = body.candidate_id ?? null;
return [{ json: { mode: candidate_id ? 'single' : 'batch', candidate_id: candidate_id ? String(candidate_id) : null } }];

const mode = $('Determine Mode').first().json.mode;
const resp = $input.first().json;
let rows = [];

if (mode === 'single') {
  rows = [resp];
} else {
  rows = resp.list || [];
}

const SINCE = '2026-05-07';

const hasText = (v) => v !== null && v !== undefined && String(v).trim().length > 0;
const hasNum = (v) => v !== null && v !== undefined && v !== '' && !Number.isNaN(Number(v));

function isGarbage(s) {
  const orig = (s || '').trim();
  const t = orig.toLowerCase();
  if (t.length === 0) return true;
  if (t.length === 1) return true;
  if (t.length === 2) {
    return !/^[A-Z]{2}$/.test(orig);
  }
  if (t.length > 80) return true;
  const noValues = new Set([
    'n/a','na','none','nil','null','tbd','test','-','--','...',
    '?','??','xx','xxx','abc','asdf','qwerty'
  ]);
  if (noValues.has(t)) return true;
  if (!/[aeiou]/.test(t)) return true;
  return false;
}

function detectLinkType(rawUrl) {
  const url = (rawUrl || '').trim();
  const u = url.toLowerCase();
  if (!u) return { type: 'icloud', url, original: url, file_id: null, note: 'empty link' };

  // Google Drive — rewrite to direct download URL with confirm=t to bypass virus-scan warning
  const gdriveFileMatch = url.match(/drive\.google\.com\/file\/d\/([a-zA-Z0-9_-]+)/);
  if (gdriveFileMatch) {
    return { type: 'pdf', url: 'https://drive.google.com/uc?export=download&confirm=t&id=' + gdriveFileMatch[1], original: url, file_id: null };
  }
  const gdriveIdMatch = url.match(/drive\.google\.com\/(?:open|uc)\?[^#]*[?&]id=([a-zA-Z0-9_-]+)/);
  if (gdriveIdMatch) {
    return { type: 'pdf', url: 'https://drive.google.com/uc?export=download&confirm=t&id=' + gdriveIdMatch[1], original: url, file_id: null };
  }
  if (/drive\.google\.com\//.test(u)) {
    return { type: 'pdf', url, original: url, file_id: null };
  }

  // Vercel Blob (public or private with presigned ?download=1)
  if (/\.public\.blob\.vercel-storage\.com\//.test(u) || /\.private\.blob\.vercel-storage\.com\//.test(u)) {
    return { type: 'pdf', url, original: url, file_id: null };
  }

  // LinkedIn
  if (/(?:^|\.|\/)linkedin\.com\//.test(u)) {
    return { type: 'linkedin', url, original: url, file_id: null };
  }

  // iCloud Drive (cannot scrape)
  if (/icloud\.com\/iclouddrive/.test(u)) {
    return { type: 'icloud', url, original: url, file_id: null };
  }

  // Anything ending in .pdf or with .pdf? in path → try as PDF
  if (/\.pdf(\?|$)/.test(u)) {
    return { type: 'pdf', url, original: url, file_id: null };
  }

  // Unknown: still try as PDF; if it's HTML the parser will fail gracefully
  return { type: 'pdf', url, original: url, file_id: null };
}

const keep = rows.filter(r => {
  if (!hasText(r['cv drive link'])) return false;
  if (mode !== 'single' && r.CreatedAt) {
    const created = String(r.CreatedAt).slice(0, 10);
    if (created < SINCE) return false;
  }
  if (isGarbage(r.position))   return false;
  if (isGarbage(r.department)) return false;
  if (mode !== 'single') {
    const fullyDone = hasText(r['extracted resume']) && hasNum(r['LLM score']) && Number(r['LLM score']) > 0;
    if (fullyDone) return false;
  }
  return true;
});

return keep.map(r => {
  const link = detectLinkType(r['cv drive link']);
  return {
    json: {
      candidate_id: String(r.Id ?? r.id),
      name: ((r['first name'] || '') + ' ' + (r['last name'] || '')).trim(),
      email: r.email || null,
      phone: r['phone number'] || null,
      department: r.department || null,
      position: r.position || null,
      cover_letter: r['cover letter'] || null,
      cv_drive_link: link.url,
      cv_drive_link_original: link.original,
      link_type: link.type
    }
  };
});

const ROLE_SUFFIXES = new Set([
  'engineer','developer','scientist','manager','specialist','analyst',
  'lead','senior','junior','principal','staff','associate',
  'intern','executive','admin','administrator','support',
  'technician','technologist','tester','designer',
  'owner','consultant','representative','rep','officer','assessor'
]);
const STOP = new Set(['the','a','an','of','and','or','in','for','to','with']);

function tokenize(s) {
  return (s || '').toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim().split(/\s+/)
    .filter(w => w.length >= 2)
    .filter(w => !STOP.has(w));
}
function domainTokens(s) {
  return new Set(tokenize(s).filter(w => !ROLE_SUFFIXES.has(w)));
}
function similarity(a, b) {
  const da = domainTokens(a);
  const db = domainTokens(b);
  if (da.size === 0 || db.size === 0) {
    const ta = new Set(tokenize(a));
    const tb = new Set(tokenize(b));
    if (ta.size === 0 || tb.size === 0) return 0;
    const c = [...ta].filter(w => tb.has(w)).length;
    return c / Math.max(ta.size, tb.size);
  }
  const c = [...da].filter(w => db.has(w)).length;
  return c / Math.max(da.size, db.size);
}

const candidate = $json;
const jdList = ($('List All JDs').first().json.list) || [];
const pos = (candidate.position || '').trim();

const exact = jdList.find(j => (j.Position || '').trim().toLowerCase() === pos.toLowerCase());
if (exact) {
  return { json: { ...candidate, jd_text: exact['Job Description'] || '', matched_position: exact.Position, match_source: 'exact', similarity: 1 } };
}

const FUZZY_THRESHOLD = 0.5;
const scored = jdList.map(j => ({ jd: j, sim: similarity(pos, j.Position) })).sort((a, b) => b.sim - a.sim);
const best = scored[0];
if (best && best.sim >= FUZZY_THRESHOLD) {
  return { json: { ...candidate, jd_text: best.jd['Job Description'] || '', matched_position: best.jd.Position, match_source: 'fuzzy', similarity: best.sim } };
}

return { json: { ...candidate, jd_text: null, matched_position: null, match_source: 'none', similarity: 0 } };

